 343 |         // Detect function start: `fn name(` or `pub fn name(` or `async fn ...`
 344 |         let is_fn = (line.contains("fn ") && line.contains('('))
 345 |             && !line.starts_with("//")
 346 |             && !line.starts_with("*");
 347 | 
 348 |         if is_fn {
 349 |             let fn_start = i;
 350 |             // Extract function name.
 351 |             let name = line
 352 |                 .split("fn ")
 353 |                 .nth(1)
 354 |                 .and_then(|s| s.split('(').next())
 355 |                 .unwrap_or("?")
 356 |                 .trim();
 357 | 
 358 |             // Count LOC and max nesting depth until matching closing brace.
 359 |             let mut depth: i32 = 0;
 360 |             let mut max_depth: i32 = 0;
 361 |             let mut fn_loc = 0;
 362 |             let mut started = false;
 363 |             let mut j = i;
 364 |             while j < lines.len() {
 365 |                 let l = lines[j];
 366 |                 for ch in l.chars() {
 367 |                     if ch == '{' {
 368 |                         depth += 1;
 369 |                         started = true;
 370 |                         if depth > max_depth {
 371 |                             max_depth = depth;
 372 |                         }
 373 |                     } else if ch == '}' {
 374 |                         depth -= 1;
 375 |                     }
 376 |                 }
 377 |                 if started {
 378 |                     fn_loc += 1;
 379 |                 }
 380 |                 if started && depth == 0 {
 381 |                     break;
 382 |                 }
 383 |                 j += 1;
 384 |             }
 385 | 
 386 |             if fn_loc > MAX_FUNCTION_LOC {
 387 |                 findings.push(SlopFinding {
 388 |                     rule: "complexity".into(),
 389 |                     message: format!(
