 391 |                         fn_start + 1
 392 |                     ),
 393 |                     file: None,
 394 |                     line: Some(fn_start + 1),
 395 |                 });
 396 |             }
 397 |             if max_depth as usize > MAX_NESTING_DEPTH {
 398 |                 findings.push(SlopFinding {
 399 |                     rule: "complexity".into(),
 400 |                     message: format!(
 401 |                         "`{name}` at line {} has nesting depth {max_depth} (max {MAX_NESTING_DEPTH}) — consider early returns or extraction",
 402 |                         fn_start + 1
 403 |                     ),
 404 |                     file: None,
 405 |                     line: Some(fn_start + 1),
 406 |                 });
 407 |             }
 408 | 
 409 |             i = j + 1;
 410 |         } else {
